mapper.select:
SELECT o.*,
       buyer.user_name AS user_name,
       buyer.user_avatar AS user_avatar,
       p.name AS product_title,
       p.cover_list AS product_cover,
       p.user_id AS seller_id,
       seller.user_name AS seller_name,
       seller.user_avatar AS seller_avatar
FROM orders o
       LEFT JOIN user buyer ON buyer.id = o.user_id
       LEFT JOIN product p ON p.id = o.product_id
       LEFT JOIN user seller ON seller.id = p.user_id


    AND o.id = #{id}


    AND o.code LIKE concat('%', #{code}, '%')


    AND o.detail LIKE concat('%', #{detail}, '%')


    AND o.user_id = #{userId}


    AND o.product_id = #{productId}


    AND o.trade_status = #{tradeStatus}


    AND o.refund_status = #{refundStatus}


    AND o.create_time BETWEEN #{startTime} AND #{endTime}


ORDER BY o.id DESC

  LIMIT #{current}, #{size}

SELECT COUNT(*)
FROM orders o


    AND o.id = #{id}


    AND o.code LIKE concat('%', #{code}, '%')


    AND o.detail LIKE concat('%', #{detail}, '%')


    AND o.user_id = #{userId}


    AND o.product_id = #{productId}


    AND o.trade_status = #{tradeStatus}


    AND o.refund_status = #{refundStatus}


    AND o.create_time BETWEEN #{startTime} AND #{endTime}
